import React, { useState } from 'react';
import './App.css';

const inputStyle = {
  padding: '12px',
  borderRadius: '8px',
  border: '1px solid #ddd',
  outline: 'none'
};

function App() {
  const [showAuth, setShowAuth] = useState(false);
  const [isLogin, setIsLogin] = useState(true);
  const [view, setView] = useState('home');
  const [activeTab, setActiveTab] = useState('home');
  const [selectedItem, setSelectedItem] = useState(null);
  const [isVerified, setIsVerified] = useState(false);
  const [userName, setUserName] = useState('');

  const items = [
    { id: 1, name: "Raket Yonex Astrox 100 ZZ", price: "50.000", category: "Badminton", img: "/astrox.jpg", desc: "Kondisi 95% mulus, senar baru ditarik 28 lbs. Cocok untuk pemain tipe menyerang.", owner: "Jordan", location: "Jakarta Barat" },
    { id: 2, name: "Sepatu Bola Adidas F50", price: "120.000", category: "Football", img: "/f50.jpg", desc: "Size 42. Ringan banget, enak buat lari kencang. Baru dipakai 2 kali di lapangan rumput.", owner: "Gilbert", location: "Tangerang" },
    { id: 3, name: "Dumbbell 10Kg", price: "30.000", category: "Fitness", img: "/dumbbell.jpg", desc: "Bahan besi solid, grip karet tidak licin. Ada sepasang (2 pcs).", owner: "Raymond", location: "Jakarta Selatan" },
  ];

  const handleSewaClick = (item) => {
    setSelectedItem(item);
    setView('detail');
  };

  const handleBack = () => {
    setView('home');
    setSelectedItem(null);
  };

  return (
    <>
      {/* Modal Authentication */}
      {showAuth && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.8)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 }}>
          <div style={{ backgroundColor: 'white', padding: '40px', borderRadius: '24px', width: '380px', position: 'relative' }}>
            <button onClick={() => setShowAuth(false)} style={{ position: 'absolute', top: '20px', right: '20px', border: 'none', background: '#eee', width: '30px', height: '30px', borderRadius: '50%', cursor: 'pointer', fontWeight: 'bold' }}>✕</button>

            <h2 style={{ textAlign: 'center', color: '#1a1a1a', marginBottom: '10px' }}>
              {isLogin ? 'Welcome Back' : 'Join GearShare'}
            </h2>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px', marginTop: '20px' }}>
              {!isLogin && (
                <>
                  <input type="text" placeholder="Nama Lengkap" style={inputStyle} onChange={(e) => setUserName(e.target.value)} />
                  <div style={{ padding: '15px', border: '2px dashed #007bff', borderRadius: '12px', textAlign: 'center', backgroundColor: '#f0f7ff' }}>
                    <span style={{ fontSize: '12px', color: '#007bff', fontWeight: 'bold' }}>Upload Foto KTP</span>
                    <input type="file" style={{ fontSize: '10px', marginTop: '5px' }} />
                  </div>
                </>
              )}
              <input type="email" placeholder="Email" style={inputStyle} />
              <input type="password" placeholder="Password" style={inputStyle} />

              <button
                onClick={() => {
                  if (!isLogin) setIsVerified(true); // Otomatis verif pas daftar (simulasi)
                  setShowAuth(false);
                }}
                style={{ padding: '14px', backgroundColor: '#1a1a1a', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', fontSize: '16px' }}
              >
                {isLogin ? 'Sign In' : 'Daftar & Verifikasi'}
              </button>

              <p style={{ textAlign: 'center', fontSize: '14px', color: '#666' }}>
                {isLogin ? "Don't have an account?" : "Already have an account?"}
                <span onClick={() => setIsLogin(!isLogin)} style={{ color: '#007bff', cursor: 'pointer', fontWeight: 'bold', marginLeft: '5px' }}>
                  {isLogin ? 'Register' : 'Login'}
                </span>
              </p>
            </div>
          </div>
        </div>
      )}

      <div style={{ backgroundColor: '#fcfcfc', minHeight: '100vh', fontFamily: "'Inter', 'Segoe UI', sans-serif" }}>
        {/* Navbar */}
        <nav style={{ backgroundColor: '#ffffff', padding: '15px 60px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 2px 15px rgba(0,0,0,0.03)', position: 'sticky', top: 0, zIndex: 100 }}>
          <h1 onClick={() => { setView('home'); setActiveTab('home') }} style={{ color: '#1a1a1a', margin: 0, fontSize: '22px', fontWeight: '900', cursor: 'pointer', letterSpacing: '-1px' }}>GEAR<span style={{ color: '#007bff' }}>SHARE</span></h1>

          <div style={{ display: 'flex', gap: '35px' }}>
            {['home', 'products', 'guide', 'about us'].map((tab) => (
              <span
                key={tab}
                onClick={() => { setActiveTab(tab); setView('home') }}
                style={{
                  cursor: 'pointer', fontWeight: '600', textTransform: 'uppercase', fontSize: '13px', letterSpacing: '1px',
                  color: activeTab === tab ? '#007bff' : '#999',
                  borderBottom: activeTab === tab ? '2px solid #007bff' : '2px solid transparent',
                  paddingBottom: '5px', transition: '0.3s'
                }}
              >
                {tab}
              </span>
            ))}
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <button onClick={() => { setIsLogin(true); setShowAuth(true) }} style={{ background: 'none', border: 'none', fontWeight: '700', color: '#1a1a1a', cursor: 'pointer', fontSize: '14px' }}>LOGIN</button>
            <button onClick={() => { setIsLogin(false); setShowAuth(true) }} style={{ backgroundColor: '#1a1a1a', color: 'white', padding: '10px 24px', borderRadius: '8px', border: 'none', fontWeight: '700', cursor: 'pointer', fontSize: '14px' }}>JOIN NOW</button>
          </div>
        </nav>

        <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '40px 20px' }}>

          {view === 'home' && (
            <>
              {/* Hero Section - Revised Colors */}
              {activeTab === 'home' && (
                <div style={{
                  textAlign: 'center', padding: '120px 20px', marginBottom: '80px',
                  background: 'linear-gradient(rgba(10, 25, 47, 0.85), rgba(10, 25, 47, 0.95)), url("https://images.unsplash.com/photo-1517836357463-d25dfeac3438?auto=format&fit=crop&q=80&w=1500") center/cover',
                  borderRadius: '30px', color: 'white'
                }}>
                  <div style={{ maxWidth: '700px', margin: '0 auto' }}>
                    <h1 style={{ fontSize: '64px', fontWeight: '900', marginBottom: '20px', lineHeight: '1', letterSpacing: '-2px' }}>
                      Gear Up, <br /> <span style={{ borderBottom: '6px solid #007bff' }}>Pay Less.</span>
                    </h1>
                    <p style={{ fontSize: '18px', opacity: 0.8, maxWidth: '500px', margin: '0 auto', lineHeight: '1.6' }}>
                      Premium sports equipment rental from your local community. Professional gear, amateur prices.
                    </p>
                    <div style={{ marginTop: '40px', display: 'flex', gap: '15px', justifyContent: 'center' }}>
                      <button onClick={() => setActiveTab('products')} style={{ padding: '18px 35px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '12px', fontWeight: '800', cursor: 'pointer' }}>
                        Browse Gear
                      </button>
                      <button onClick={() => setActiveTab('guide')} style={{ padding: '18px 35px', backgroundColor: 'rgba(255,255,255,0.1)', color: 'white', border: '1px solid rgba(255,255,255,0.2)', borderRadius: '12px', fontWeight: '700', cursor: 'pointer', backdropFilter: 'blur(10px)' }}>
                        How it Works
                      </button>
                    </div>
                  </div>
                </div>
              )}

              {/* Halaman Guide - Cleaner Look */}
              {activeTab === 'guide' && (
                <div style={{ padding: '20px 0', maxWidth: '800px', margin: '0 auto' }}>
                  <h1 style={{ fontSize: '42px', fontWeight: '900', textAlign: 'center', marginBottom: '50px', letterSpacing: '-1px' }}>Getting Started</h1>
                  <div style={{ display: 'grid', gap: '20px' }}>
                    {[
                      { n: '01', t: 'Find Your Gear', d: 'Search through our curated collection of professional sports equipment near you.', c: '#007bff' },
                      { n: '02', t: 'Verify & Book', d: 'Secure your rental with our quick ID verification system. Simple and safe.', c: '#1a1a1a' },
                      { n: '03', t: 'Pickup & Play', d: 'Connect with the owner, grab your gear, and hit the field. It’s that easy.', c: '#007bff' }
                    ].map(step => (
                      <div key={step.n} style={{ display: 'flex', alignItems: 'center', gap: '30px', backgroundColor: 'white', padding: '40px', borderRadius: '20px', border: '1px solid #eee' }}>
                        <span style={{ fontSize: '48px', fontWeight: '900', color: step.c, opacity: 0.2 }}>{step.n}</span>
                        <div>
                          <h3 style={{ fontSize: '22px', marginBottom: '5px' }}>{step.t}</h3>
                          <p style={{ color: '#666', lineHeight: '1.5' }}>{step.d}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Halaman Products */}
              {(activeTab === 'products' || activeTab === 'home') && (
                <>
                  <div style={{ marginBottom: '40px' }}>
                    <h2 style={{ fontSize: '32px', fontWeight: '900', margin: 0, letterSpacing: '-1px' }}>{activeTab === 'products' ? 'Available Gear' : 'Featured Collections'}</h2>
                    <div style={{ width: '50px', height: '4px', backgroundColor: '#007bff', marginTop: '10px' }}></div>
                  </div>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '40px' }}>
                    {items.map(item => (
                      <div key={item.id} style={{ backgroundColor: '#fff', borderRadius: '24px', overflow: 'hidden', border: '1px solid #f0f0f0', transition: '0.3s hover' }}>
                        <div style={{ position: 'relative' }}>
                          <img src={item.img} alt={item.name} style={{ width: '100%', height: '240px', objectFit: 'cover' }} />
                          <span style={{ position: 'absolute', top: '20px', left: '20px', backgroundColor: 'white', padding: '5px 12px', borderRadius: '20px', fontSize: '11px', fontWeight: '800', boxShadow: '0 4px 10px rgba(0,0,0,0.1)' }}>{item.category}</span>
                        </div>
                        <div style={{ padding: '30px' }}>
                          <h3 style={{ fontSize: '18px', fontWeight: '700', margin: '0 0 10px 0' }}>{item.name}</h3>
                          <p style={{ fontSize: '22px', fontWeight: '900', color: '#1a1a1a', margin: 0 }}>Rp {item.price} <span style={{ fontSize: '14px', color: '#999', fontWeight: '400' }}>/ day</span></p>
                          <button onClick={() => handleSewaClick(item)} style={{ width: '100%', marginTop: '25px', padding: '15px', backgroundColor: '#1a1a1a', color: 'white', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: '800', transition: '0.2s' }}>Rent Now</button>
                        </div>
                      </div>
                    ))}
                  </div>
                </>
              )}
            </>
          )}

          {/* View Detail - Premium Polish */}
          {view === 'detail' && (
            <div style={{ display: 'flex', gap: '60px', alignItems: 'start' }}>
              <div style={{ flex: 1 }}>
                <button onClick={handleBack} style={{ marginBottom: '30px', border: 'none', background: '#f0f0f0', padding: '12px 25px', borderRadius: '10px', cursor: 'pointer', fontWeight: '700' }}>← BACK</button>
                <img src={selectedItem.img} alt={selectedItem.name} style={{ width: '100%', borderRadius: '30px', boxShadow: '0 20px 40px rgba(0,0,0,0.1)' }} />
              </div>
              <div style={{ flex: 1.2, padding: '40px 0' }}>
                <span style={{ color: '#007bff', fontWeight: '900', fontSize: '14px', letterSpacing: '2px' }}>{selectedItem.category}</span>
                <h2 style={{ fontSize: '48px', fontWeight: '900', margin: '10px 0 20px 0', letterSpacing: '-2px' }}>{selectedItem.name}</h2>
                <p style={{ fontSize: '32px', fontWeight: '900', color: '#1a1a1a' }}>Rp {selectedItem.price} <span style={{ fontSize: '18px', color: '#999', fontWeight: '400' }}>/ day</span></p>
                <p style={{ color: '#666', lineHeight: '1.8', fontSize: '17px', marginTop: '30px' }}>{selectedItem.desc}</p>

                <div style={{ marginTop: '40px', padding: '35px', backgroundColor: 'white', borderRadius: '25px', border: '2px solid #1a1a1a' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                    <span style={{ fontWeight: '700' }}>Rental Duration:</span>
                    <span>1 Day</span>
                  </div>
                  <button onClick={() => alert(`Order Confirmed!`)} style={{ width: '100%', padding: '20px', backgroundColor: '#1a1a1a', color: 'white', border: 'none', borderRadius: '15px', fontWeight: '900', fontSize: '18px', cursor: 'pointer' }}>
                    CONFIRM RENTAL
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </>
  );
}

export default App;
